#!/usr/bin/env node

/*
 * Posts accumulated-action markdown text to the CRM actions API.
 * Intended input is one or more actions-YYYY-MM-DD.md files generated by
 * scripts/build-accumulated-actions.js. Default behavior is one API post per
 * file, with the full markdown body stored in the action field.
 */

const fs = require('fs');
const path = require('path');

const workspaceRoot = path.resolve(__dirname, '..');
const envFilePath = path.join(workspaceRoot, '.env');
const postRoutePath = '/api/data/actions';

function parseEnvValue(rawValue) {
  const trimmed = rawValue.trim();
  if (!trimmed) {
    return '';
  }

  const quote = trimmed[0];
  if ((quote === '"' || quote === "'") && trimmed.endsWith(quote)) {
    const inner = trimmed.slice(1, -1);
    if (quote === '"') {
      return inner
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\r')
        .replace(/\\t/g, '\t');
    }
    return inner;
  }

  const commentIndex = trimmed.indexOf(' #');
  if (commentIndex >= 0) {
    return trimmed.slice(0, commentIndex).trim();
  }

  return trimmed;
}

function loadDotEnv(filePath) {
  if (!fs.existsSync(filePath)) {
    return;
  }

  const lines = fs.readFileSync(filePath, 'utf8').split(/\r?\n/);
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) {
      continue;
    }

    const normalized = trimmed.startsWith('export ') ? trimmed.slice('export '.length) : trimmed;
    const equalsIndex = normalized.indexOf('=');
    if (equalsIndex <= 0) {
      continue;
    }

    const key = normalized.slice(0, equalsIndex).trim();
    if (!key || Object.prototype.hasOwnProperty.call(process.env, key)) {
      continue;
    }

    process.env[key] = parseEnvValue(normalized.slice(equalsIndex + 1));
  }
}

function getRequiredEnv(name) {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function envFlagEnabled(name) {
  const value = String(process.env[name] || '').trim().toLowerCase();
  return value === '1' || value === 'true' || value === 'yes';
}

function requireWriteEnabled() {
  if (!envFlagEnabled('AIW_ENABLE_CRM_ACTION_POST')) {
    throw new Error('CRM action posting is disabled. Set AIW_ENABLE_CRM_ACTION_POST=1 to allow POST /api/data/actions.');
  }
}

function printHelp() {
  console.log(`Usage:
  node scripts/post-accumulated-actions.js data/0/daily-triage/2026/05/20/actions-2026-05-20.md --dry-run
  node scripts/post-accumulated-actions.js data/0/daily-triage/2026/05/20/actions-2026-05-20.md data/6/daily-triage/2026/05/20/actions-2026-05-20.md
  node scripts/post-accumulated-actions.js --file=data/0/daily-triage/2026/05/20/actions-2026-05-20.md
  rg --files data | rg '^data/[0-9]+/daily-triage/2026/.+/actions-2026-.+\\.md$' | node scripts/post-accumulated-actions.js --files-from=- --dry-run
  cat actions-2026-05-20.md | node scripts/post-accumulated-actions.js --stdin --date=2026-05-20 --dry-run

Options:
  --file PATH         Markdown file to read. Can be used multiple times.
  --files-from PATH   Read newline-delimited markdown file paths. Use - for stdin.
  --stdin            Read markdown from stdin.
  --date YYYY-MM-DD  Override the action date. Otherwise uses the markdown As-of date or filename date.
  --split-actions    Post one row per unchecked checkbox action instead of one row per full file.
  --skip-existing    Read existing actions by date and skip exact duplicate payloads.
  --include-checked  Include checked markdown tasks. Default: only unchecked tasks.
  --dry-run          Parse and print payloads without posting.
  --quiet            Print only the final count.
  --json             Print JSON result instead of a compact summary.
  -h, --help         Show this help.

Environment:
  CRM_BASE_URL and CRM_ACCESS_TOKEN are required for posting.
  AIW_ENABLE_CRM_ACTION_POST=1 is required unless --dry-run is used.
`);
}

function parseArgs(argv) {
  const args = {
    filePaths: [],
    filesFrom: null,
    stdin: false,
    date: null,
    dryRun: false,
    json: false,
    quiet: false,
    splitActions: false,
    skipExisting: false,
    includeChecked: false,
    help: false,
  };

  for (let index = 0; index < argv.length; index += 1) {
    const part = argv[index];

    if (part === '--help' || part === '-h') {
      args.help = true;
      continue;
    }
    if (part === '--stdin') {
      args.stdin = true;
      continue;
    }
    if (part === '--dry-run') {
      args.dryRun = true;
      continue;
    }
    if (part === '--json') {
      args.json = true;
      continue;
    }
    if (part === '--quiet') {
      args.quiet = true;
      continue;
    }
    if (part === '--split-actions') {
      args.splitActions = true;
      continue;
    }
    if (part === '--skip-existing') {
      args.skipExisting = true;
      continue;
    }
    if (part === '--include-checked') {
      args.includeChecked = true;
      continue;
    }
    if (part === '--file') {
      const value = argv[index + 1];
      if (!value) {
        throw new Error('Missing value after --file.');
      }
      args.filePaths.push(value);
      index += 1;
      continue;
    }
    if (part === '--files-from') {
      const value = argv[index + 1];
      if (!value) {
        throw new Error('Missing value after --files-from.');
      }
      args.filesFrom = value;
      index += 1;
      continue;
    }
    if (part.startsWith('--file=')) {
      args.filePaths.push(part.slice('--file='.length));
      continue;
    }
    if (part.startsWith('--files-from=')) {
      args.filesFrom = part.slice('--files-from='.length);
      continue;
    }
    if (part === '--date') {
      const value = argv[index + 1];
      if (!value) {
        throw new Error('Missing value after --date.');
      }
      args.date = value;
      index += 1;
      continue;
    }
    if (part.startsWith('--date=')) {
      args.date = part.slice('--date='.length);
      continue;
    }
    if (part.startsWith('-')) {
      throw new Error(`Unknown option: ${part}`);
    }
    args.filePaths.push(part);
  }

  if (args.filesFrom) {
    const list = args.filesFrom === '-'
      ? readStdin()
      : fs.readFileSync(path.resolve(workspaceRoot, args.filesFrom), 'utf8');
    args.filePaths.push(...list.split(/\r?\n/).map((line) => line.trim()).filter(Boolean));
  }

  if (args.stdin && (args.filePaths.length > 0 || args.filesFrom)) {
    throw new Error('Use either --stdin or file path input, not both.');
  }
  if (!args.help && !args.stdin && args.filePaths.length === 0) {
    throw new Error('Provide an actions markdown file path or --stdin.');
  }
  if (args.date) {
    validateIsoDate(args.date, '--date');
  }

  return args;
}

function validateIsoDate(value, label) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    throw new Error(`${label} must be YYYY-MM-DD.`);
  }
}

function readStdin() {
  return fs.readFileSync(0, 'utf8');
}

function readInput(args) {
  if (args.stdin) {
    return [{
      markdown: readStdin(),
      inputPath: null,
    }];
  }

  return args.filePaths.map((filePath) => {
    const inputPath = path.resolve(workspaceRoot, filePath);
    return {
      markdown: fs.readFileSync(inputPath, 'utf8'),
      inputPath,
    };
  });
}

function compact(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function inferDate(markdown, inputPath, overrideDate) {
  if (overrideDate) {
    return overrideDate;
  }

  const asOfMatch = markdown.match(/^- As-of date:\s*(\d{4}-\d{2}-\d{2})\s*$/m);
  if (asOfMatch) {
    return asOfMatch[1];
  }

  if (inputPath) {
    const filenameMatch = path.basename(inputPath).match(/actions-(\d{4}-\d{2}-\d{2})\.md$/);
    if (filenameMatch) {
      return filenameMatch[1];
    }
  }

  throw new Error('Could not infer action date. Pass --date=YYYY-MM-DD.');
}

function parseObjectKey(line) {
  const match = line.match(/^- (Account|Contact) key:\s*(account|contact):(\d+)\s*$/i);
  if (!match) {
    return null;
  }
  return {
    objectType: match[2].toLowerCase(),
    objectId: Number(match[3]),
  };
}

function parseActionLine(line) {
  const match = line.match(/^- \[([ xX])\]\s+(.+)$/);
  if (!match) {
    return null;
  }
  const action = compact(match[2]);
  if (!action) {
    return null;
  }
  return {
    checked: match[1].toLowerCase() === 'x',
    action,
  };
}

function parseAccumulatedActionMarkdown(markdown, date, options = {}) {
  const rows = [];
  const seen = new Set();
  let currentObject = null;
  let inActionsSection = false;

  for (const rawLine of markdown.split(/\r?\n/)) {
    const line = rawLine.trim();

    if (/^###\s+/.test(line)) {
      currentObject = null;
      inActionsSection = false;
      continue;
    }

    const objectKey = parseObjectKey(line);
    if (objectKey) {
      currentObject = objectKey;
      inActionsSection = false;
      continue;
    }

    if (/^####\s+Actions\s*$/i.test(line)) {
      if (!currentObject) {
        throw new Error('Found an Actions section before an Account key or Contact key.');
      }
      inActionsSection = true;
      continue;
    }

    if (/^####\s+/.test(line)) {
      inActionsSection = false;
      continue;
    }

    if (!inActionsSection) {
      continue;
    }

    const parsedAction = parseActionLine(line);
    if (!parsedAction || (parsedAction.checked && !options.includeChecked)) {
      continue;
    }

    const row = {
      accountId: currentObject.objectType === 'account' ? currentObject.objectId : null,
      contactId: currentObject.objectType === 'contact' ? currentObject.objectId : null,
      date,
      action: parsedAction.action,
    };
    const key = `${row.accountId || ''}:${row.contactId || ''}:${row.date}:${row.action.toLowerCase()}`;
    if (seen.has(key)) {
      continue;
    }
    seen.add(key);
    rows.push(row);
  }

  return rows;
}

function buildWholeFilePayload(markdown, date) {
  const action = markdown.trim();
  if (!action) {
    throw new Error('Markdown input is empty.');
  }
  return {
    accountId: null,
    contactId: null,
    date,
    action,
  };
}

function buildPayloadsForInputs(inputs, args) {
  const payloads = [];
  for (const input of inputs) {
    const date = inferDate(input.markdown, input.inputPath, args.date);
    const inputPayloads = args.splitActions
      ? parseAccumulatedActionMarkdown(input.markdown, date, { includeChecked: args.includeChecked })
      : [buildWholeFilePayload(input.markdown, date)];

    for (const payload of inputPayloads) {
      payloads.push({
        payload,
        inputPath: input.inputPath,
      });
    }
  }
  return payloads;
}

function buildUrl(baseUrl, routePath, queryParams = {}) {
  const url = new URL(routePath.replace(/^\//, ''), `${baseUrl.replace(/\/+$/, '')}/`);
  for (const [key, value] of Object.entries(queryParams)) {
    if (value !== undefined && value !== null) {
      url.searchParams.set(key, String(value));
    }
  }
  return url;
}

function authHeader(token) {
  return /^Bearer\s+/i.test(token) ? token : `Bearer ${token}`;
}

async function fetchJson(baseUrl, token, routePath, label, queryParams = {}) {
  const response = await fetch(buildUrl(baseUrl, routePath, queryParams), {
    headers: {
      Authorization: authHeader(token),
      Accept: 'application/json',
    },
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(`${label} failed (${response.status} ${response.statusText}): ${body.slice(0, 500)}`);
  }

  return response.json();
}

function extractList(payload) {
  if (Array.isArray(payload)) {
    return payload;
  }
  if (payload && Array.isArray(payload.items)) {
    return payload.items;
  }
  if (payload && Array.isArray(payload.data)) {
    return payload.data;
  }
  if (payload && Array.isArray(payload.results)) {
    return payload.results;
  }
  return [];
}

function isoDate(value) {
  if (!value) {
    return '';
  }
  return String(value).slice(0, 10);
}

function payloadKey(payload) {
  return [
    payload.accountId == null ? '' : String(payload.accountId),
    payload.contactId == null ? '' : String(payload.contactId),
    isoDate(payload.date),
    payload.action,
  ].join('\u001f');
}

async function fetchExistingActionKeys(baseUrl, token, date) {
  const payload = await fetchJson(baseUrl, token, postRoutePath, `GET ${postRoutePath}`, { date });
  const keys = new Set();
  for (const row of extractList(payload)) {
    keys.add(payloadKey({
      accountId: row.accountId ?? null,
      contactId: row.contactId ?? null,
      date: row.date,
      action: row.action,
    }));
  }
  return keys;
}

async function filterExistingActions(baseUrl, token, payloads) {
  const keysByDate = new Map();
  const filtered = [];
  const skipped = [];

  for (const item of payloads) {
    const date = isoDate(item.payload.date);
    if (!keysByDate.has(date)) {
      keysByDate.set(date, await fetchExistingActionKeys(baseUrl, token, date));
    }

    const existingKeys = keysByDate.get(date);
    const key = payloadKey(item.payload);
    if (existingKeys.has(key)) {
      skipped.push(item);
      continue;
    }
    existingKeys.add(key);
    filtered.push(item);
  }

  return { filtered, skipped };
}

async function postAction(baseUrl, token, payload) {
  const authorization = /^Bearer\s+/i.test(token) ? token : `Bearer ${token}`;
  const response = await fetch(buildUrl(baseUrl, postRoutePath), {
    method: 'POST',
    headers: {
      Authorization: authorization,
      Accept: 'application/json',
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  const responseText = await response.text();
  let body = responseText;
  if (responseText) {
    try {
      body = JSON.parse(responseText);
    } catch {
      body = responseText;
    }
  }

  if (!response.ok) {
    throw new Error(`POST ${postRoutePath} failed (${response.status} ${response.statusText}): ${responseText.slice(0, 500)}`);
  }

  return {
    status: response.status,
    body,
  };
}

async function postActions(baseUrl, token, payloads) {
  const results = [];
  for (const item of payloads) {
    const result = await postAction(baseUrl, token, item.payload);
    results.push({
      payload: item.payload,
      inputPath: item.inputPath,
      ...result,
    });
  }
  return results;
}

function summarizePayload(payload) {
  const target = payload.accountId ? `account:${payload.accountId}` : payload.contactId ? `contact:${payload.contactId}` : 'markdown-file';
  const preview = payload.action.length > 120 ? `${payload.action.slice(0, 117)}...` : payload.action;
  return `${target} ${payload.date} - ${preview}`;
}

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.help) {
    printHelp();
    return;
  }

  const inputs = readInput(args);
  const payloads = buildPayloadsForInputs(inputs, args);

  if (payloads.length === 0) {
    throw new Error('No action payloads found in the markdown input.');
  }

  if (args.dryRun) {
    if (args.json) {
      console.log(JSON.stringify({
        dry_run: true,
        mode: args.splitActions ? 'split-actions' : 'whole-file',
        route: postRoutePath,
        count: payloads.length,
        payloads: payloads.map((item) => ({
          input_path: item.inputPath ? path.relative(workspaceRoot, item.inputPath).split(path.sep).join('/') : null,
          ...item.payload,
        })),
      }, null, 2));
      return;
    }

    console.log(`Dry run: parsed ${payloads.length} action payloads for POST ${postRoutePath}.`);
    if (!args.quiet) {
      for (const item of payloads) {
        console.log(`- ${summarizePayload(item.payload)}`);
      }
    }
    return;
  }

  loadDotEnv(envFilePath);
  requireWriteEnabled();
  const baseUrl = getRequiredEnv('CRM_BASE_URL');
  const token = getRequiredEnv('CRM_ACCESS_TOKEN');
  const deduped = args.skipExisting
    ? await filterExistingActions(baseUrl, token, payloads)
    : { filtered: payloads, skipped: [] };
  const results = await postActions(baseUrl, token, deduped.filtered);

  if (args.json) {
    console.log(JSON.stringify({
      dry_run: false,
      mode: args.splitActions ? 'split-actions' : 'whole-file',
      route: postRoutePath,
      skipped_existing: deduped.skipped.length,
      posted: results.length,
      results: results.map((result) => ({
        ...result,
        inputPath: result.inputPath ? path.relative(workspaceRoot, result.inputPath).split(path.sep).join('/') : null,
      })),
    }, null, 2));
    return;
  }

  console.log(`Posted ${results.length} action payloads to ${postRoutePath}.`);
  if (args.skipExisting) {
    console.log(`Skipped ${deduped.skipped.length} existing action payloads.`);
  }
  if (!args.quiet) {
    for (const result of results) {
      console.log(`- ${summarizePayload(result.payload)} (${result.status})`);
    }
  }
}

main().catch((error) => {
  console.error(error.message || error);
  process.exitCode = 1;
});
